// Type declaration for the auto-generated asset manifest.
//
// `assets.generated.ts` is produced by `script/generate-web-assets.ts` after a
// vite build and is gitignored, so it is absent on a fresh clone and in CI.
// This declaration lets `assets.ts` typecheck without it; at build time the
// generated `.ts` provides the real values and is what the compiled binary
// bundles.
export declare const WEB_ASSETS: Record<string, string>
export declare const WEB_INDEX: string | undefined
